const allItems = $input.all();
const triggerData = $('New Policy').item.json;
const fileName = triggerData.name || 'unknown';
const fileId   = triggerData.id   || '';
const extractItem = allItems[0]?.json || {};
const policyData = extractItem.data || extractItem;
const analysisItem = allItems[1]?.json || {};
const coverageAnalysis = analysisItem.answer || analysisItem.markdown || analysisItem.text || '';

// Days until expiry
let daysLeft = 0;
if (policyData.expirationDate && policyData.expirationDate !== 'N/A') {
  const expiry = new Date(policyData.expirationDate);
  const today = new Date();
  if (!isNaN(expiry.getTime())) {
    daysLeft = Math.ceil((expiry - today) / (1000 * 60 * 60 * 24));
  }
}

// Extract rating and gap count from analysis
const ratingMatch = coverageAnalysis.match(/OVERALL RATING[:\s]+([A-Z]+)/i);
const coverageRating = ratingMatch ? ratingMatch[1] : 'N/A';
const gapMatch = coverageAnalysis.match(/GAPS COUNT[:\s]+(\d+)/i);
const gapsFound = gapMatch ? parseInt(gapMatch[1]) : (coverageAnalysis.match(/gap/gi) || []).length;

return [{ json: {
  // Policy data
  policyType: policyData.policyType || 'N/A',
  insurer: policyData.insurer || 'N/A',
  policyNumber: policyData.policyNumber || 'N/A',
  namedInsured: policyData.namedInsured || 'N/A',
  insuredAddress: policyData.insuredAddress || 'N/A',
  effectiveDate: policyData.effectiveDate || 'N/A',
  expirationDate: policyData.expirationDate || 'N/A',
  daysLeft,
  premiumAmount: policyData.premiumAmount || 0,
  premiumFrequency: policyData.premiumFrequency || 'N/A',
  deductibleAmount: policyData.deductibleAmount || 0,
  deductibleType: policyData.deductibleType || 'N/A',
  primaryCoverageLimit: policyData.primaryCoverageLimit || 0,
  liabilityCoverage: policyData.liabilityCoverage || 0,
  exclusions: policyData.exclusions || 'None listed',
  additionalInsureds: policyData.additionalInsureds || 'None',
  agentName: policyData.agentName || 'N/A',
  // Analysis
  coverageAnalysis,
  coverageRating,
  gapsFound,
  fileName,
  fileId,
  processedAt: new Date().toISOString()
}}];

